#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
	struct node
	{
		long long l,r,max1;
		long long lson,rson;
		long long tag;
		node():tag(0){}
	}a[3000010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
		a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
	}
	void pushdown(long long x)
	{
		long long mid=(a[x].l+a[x].r)>>1;
		long long ls=a[x].lson,rs=a[x].rson;
		long long tg=a[x].tag;
		a[ls].max1+=tg;
		a[rs].max1+=tg;
		a[ls].tag+=tg;
		a[rs].tag+=tg;
		a[x].tag=0;
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt,mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
			a[x].max1=0;
			return x;
		}
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	void add(long long x,long long l,long long r,long long z)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			a[x].max1+=z;
			a[x].tag+=z;
			return;
		}
		pushdown(x);
		add(a[x].lson,l,r,z);
		add(a[x].rson,l,r,z);
		pushup(x);
	}
}t;
struct node
{
    int l,r,len;
    bool operator<(const node&b)const
    {
        return len<b.len;
    }
}a[1000010];
int b[3000010];
int main()
{
    int n,m,k,tot=0;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
        a[i].len=a[i].r-a[i].l;
        b[++tot]=a[i].l;
        b[++tot]=a[i].r;
    }
    sort(b+1,b+1+tot);
    k=unique(b+1,b+1+tot)-b-1;
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        a[i].l=lower_bound(b+1,b+1+k,a[i].l)-b;
        a[i].r=lower_bound(b+1,b+1+k,a[i].r)-b;
    }
    t.init(1,k);
    int ans=INT_MAX;
    for(int i=1,j=1;i<=n;i++)
    {
        t.add(1,a[i].l,a[i].r,1);
        while(t.a[1].max1>=m&&j<=i)
        {
            ans=min(ans,a[i].len-a[j].len);
            t.add(1,a[j].l,a[j].r,-1);
            j++;
        }
    }
    if(ans>1e9)
    {
        printf("-1");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
